import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { useAuth } from '../../contexts/AuthContext';
import { useSocket } from '../../contexts/SocketContext';
import axios from 'axios';

const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000/api';

const CustomerDashboard = () => {
  const { user } = useAuth();
  const { sensorData } = useSocket();
  const [transactions, setTransactions] = useState([]);
  const [loading, setLoading] = useState(true);
  const [stats, setStats] = useState({
    totalSpent: 0,
    totalKg: 0,
    transactionCount: 0
  });

  useEffect(() => {
    fetchTransactions();
  }, []);

  const fetchTransactions = async () => {
    try {
      const response = await axios.get(`${API_URL}/transactions`);
      setTransactions(response.data.data || response.data);
      
      const data = response.data.data || response.data;
      const totalSpent = data.reduce((sum, t) => sum + (t.amountPaid || 0), 0);
      const totalKg = data.reduce((sum, t) => sum + (t.quantityKg || 0), 0);
      
      setStats({
        totalSpent,
        totalKg,
        transactionCount: data.length
      });
    } catch (error) {
      console.error('Error fetching transactions:', error);
    } finally {
      setLoading(false);
    }
  };

  if (!user?.termsAccepted) {
    return (
      <div className="bg-yellow-50 border-l-4 border-yellow-400 p-4 mb-6">
        <div className="flex">
          <div className="flex-shrink-0">
            <span className="text-yellow-400 text-xl">⚠️</span>
          </div>
          <div className="ml-3">
            <p className="text-sm text-yellow-700">
              You haven't accepted our terms and conditions yet.{' '}
              <Link to="/terms" className="font-medium underline text-yellow-700 hover:text-yellow-600">
                Click here to review and accept
              </Link>
            </p>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="container mx-auto px-4 py-8">
      <h1 className="text-3xl font-bold text-gray-800 mb-6">
        Welcome back, {user?.firstName}! 👋
      </h1>

      {/* Stats Cards */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
        <div className="bg-white rounded-lg shadow-md p-6">
          <div className="flex items-center">
            <div className="bg-green-100 rounded-full p-3 mr-4">
              <span className="text-2xl">📊</span>
            </div>
            <div>
              <p className="text-sm text-gray-600">Total Transactions</p>
              <p className="text-2xl font-bold text-gray-800">{stats.transactionCount}</p>
            </div>
          </div>
        </div>

        <div className="bg-white rounded-lg shadow-md p-6">
          <div className="flex items-center">
            <div className="bg-blue-100 rounded-full p-3 mr-4">
              <span className="text-2xl">💰</span>
            </div>
            <div>
              <p className="text-sm text-gray-600">Total Spent</p>
              <p className="text-2xl font-bold text-gray-800">₱{stats.totalSpent.toFixed(2)}</p>
            </div>
          </div>
        </div>

        <div className="bg-white rounded-lg shadow-md p-6">
          <div className="flex items-center">
            <div className="bg-yellow-100 rounded-full p-3 mr-4">
              <span className="text-2xl">🌾</span>
            </div>
            <div>
              <p className="text-sm text-gray-600">Total Rice Purchased</p>
              <p className="text-2xl font-bold text-gray-800">{stats.totalKg.toFixed(2)} kg</p>
            </div>
          </div>
        </div>
      </div>

      {/* Machine Status */}
      {sensorData && (
        <div className="bg-white rounded-lg shadow-md p-6 mb-8">
          <h2 className="text-xl font-semibold text-gray-800 mb-4">Machine Status</h2>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="border rounded-lg p-4">
              <p className="text-sm text-gray-600">Sinandomeng Rice</p>
              <div className="flex items-center justify-between mt-2">
                <span className="text-2xl font-bold text-gray-800">
                  {sensorData.container1Level?.toFixed(1)} kg
                </span>
                <span className={`px-3 py-1 rounded-full text-sm font-semibold ${
                  sensorData.container1Stock === 'OK' ? 'bg-green-100 text-green-800' :
                  sensorData.container1Stock === 'LOW' ? 'bg-yellow-100 text-yellow-800' :
                  'bg-red-100 text-red-800'
                }`}>
                  {sensorData.container1Stock}
                </span>
              </div>
            </div>
            <div className="border rounded-lg p-4">
              <p className="text-sm text-gray-600">Dinorado Rice</p>
              <div className="flex items-center justify-between mt-2">
                <span className="text-2xl font-bold text-gray-800">
                  {sensorData.container2Level?.toFixed(1)} kg
                </span>
                <span className={`px-3 py-1 rounded-full text-sm font-semibold ${
                  sensorData.container2Stock === 'OK' ? 'bg-green-100 text-green-800' :
                  sensorData.container2Stock === 'LOW' ? 'bg-yellow-100 text-yellow-800' :
                  'bg-red-100 text-red-800'
                }`}>
                  {sensorData.container2Stock}
                </span>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Recent Transactions */}
      <div className="bg-white rounded-lg shadow-md p-6 mb-8">
        <div className="flex justify-between items-center mb-4">
          <h2 className="text-xl font-semibold text-gray-800">Recent Transactions</h2>
          <Link to="/customer/transactions" className="text-green-600 hover:text-green-800">
            View All →
          </Link>
        </div>
        
        {loading ? (
          <div className="text-center py-8">
            <div className="inline-block animate-spin rounded-full h-8 w-8 border-b-2 border-green-600"></div>
          </div>
        ) : transactions.length === 0 ? (
          <div className="text-center py-8 text-gray-500">
            No transactions yet. Visit our vending machine to make your first purchase!
          </div>
        ) : (
          <div className="space-y-4">
            {transactions.slice(0, 5).map((transaction) => (
              <div key={transaction._id} className="border-b pb-4 last:border-b-0">
                <div className="flex justify-between items-center">
                  <div>
                    <p className="font-semibold text-gray-800">
                      {transaction.riceType} - {transaction.quantityKg} kg
                    </p>
                    <p className="text-sm text-gray-500">
                      {new Date(transaction.createdAt).toLocaleDateString()} at{' '}
                      {new Date(transaction.createdAt).toLocaleTimeString()}
                    </p>
                  </div>
                  <div className="text-right">
                    <p className="font-bold text-green-600">₱{transaction.amountPaid}</p>
                    <Link 
                      to={`/customer/rate/${transaction.transactionId}`}
                      className="text-sm text-green-600 hover:text-green-800"
                    >
                      Rate this purchase
                    </Link>
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* Quick Actions */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <Link 
          to="/customer/returns/create" 
          className="bg-white rounded-lg shadow-md p-6 hover:shadow-lg transition-shadow"
        >
          <div className="text-center">
            <span className="text-4xl mb-2 block">↩️</span>
            <h3 className="text-lg font-semibold text-gray-800">Request Return</h3>
            <p className="text-sm text-gray-600 mt-2">Return a product if you're not satisfied</p>
          </div>
        </Link>

        <Link 
          to="/customer/messages" 
          className="bg-white rounded-lg shadow-md p-6 hover:shadow-lg transition-shadow"
        >
          <div className="text-center">
            <span className="text-4xl mb-2 block">💬</span>
            <h3 className="text-lg font-semibold text-gray-800">Contact Support</h3>
            <p className="text-sm text-gray-600 mt-2">Send us a message or ask for help</p>
          </div>
        </Link>
      </div>
    </div>
  );
};

export default CustomerDashboard;
